SELECT [qSoloVendItemperean-step1].*, Customer.[VAT Registration No_], Customer.[Fiscal Code], DatiCarryOverESMU.[Carry Over], DatiCarryOverESMU.Smu, Item.Description, Item.[Description 2], Item.[Trademark Code], Item.[Season Code], Item.[Collection Code], Item.[Line Code], [Variable Code].Description AS Color, [Geographical Zone].Description AS GeographicalZoneDescription, Item.[Season Typology], Item.[Product Family], Item.[Product Sex], Item.[Shipment Priority], Item.[Innovation Degree], Item.[Heel Height], Item.[End Customer Price Gap], Item.[Market Segment], Item.[Product Typology], Item.[Main Material], Item.[Sole Material], [MustBuy-ArticoloColore].[Must Buy], [Geographical Zone_1].Description AS GeographicalZone2Description, Customer.[Name 2], Customer.Address, Customer.City, Customer.Contact, Customer.[Phone No_], Customer.[Country_Region Code], Customer.[Post Code], Customer.County, Customer.[Reservation Priority], Item.[Vendor No_], Vendor.Name AS Vendor, Customer.[Current Risk] AS LinceRischioOggi, Customer.[Updated Date] AS LinceAggiornamentoFile, Customer.[Updated Type] AS LinceTipoEvasione, Customer.[Due Date] AS LinceDataEvasione, Customer.[Internal Valuation], Customer.[Valuation Date], Customer.[Business E-Mail], Item.[Country_Region of Origin Code], DatiCarryOverESMU.[Sold Out], DatiCarryOverESMU.[Sold Out Date], DatiCarryOverESMU.[Sales_Purchase Status Date], Customer.[Fax No_], Val([Authorized Stores Number]) AS PuntiVendita, IIf([Store Distribution]=3,"3-Dept.Store",IIf([Store Distribution]=2,"2-Indipendent",IIf([Store Distribution]=1,"1-Chain","0-UNK"))) AS StoreDistribution, IIf([Store Image]=4,"4-Commodity",IIf([Store Image]=3,"3-Standard",IIf([Store Image]=2,"2-Premium",IIf([Store Image]=1,"1-Image","0-UNK")))) AS StoreImage, IIf([Store Type]=3,"3-Footwear",IIf([Store Type]=2,"2-Apparel-Footwear-Accessories",IIf([Store Type]=1,"1-Apparel-Footwear","0-UNK"))) AS StoreType, [NavisionEan-step0].[Cross-Reference No_] AS EAN, [NavisionEan-step0-UPC].[Cross-Reference No_] AS UPCCode, Item.[Upper Composition], Item.[Lining Composition], Item.[Outsole Composition], Item.[Insole Composition], Item.[Tariff No_], Item.[Advertising Material], [quantitysold]*Val([gross weight]) AS GrossWeightTotal, [quantitysold]*Val([net weight]) AS NetWeightTotal, [quantitysold]*Val([unit volume ]) AS VolumetTotal, IIf(IsNull([ListinoVenditaWholesale.item no_])=False,[ListinoVenditaWholesale.Listino],0) AS WholesalePrice, IIf(IsNull([ListinoVenditaRetail.item no_])=False,[ListinoVenditaRetail.Listino],0) AS RetailPrice
FROM (((((((((([qSoloVendItemperean-step1] INNER JOIN (Item INNER JOIN [Variable Code] ON Item.[Constant Assortment Var_Grp_] = [Variable Code].[Variable Group]) ON ([qSoloVendItemperean-step1].ColorCode = [Variable Code].[Variable Code]) AND ([qSoloVendItemperean-step1].Article = Item.No_)) LEFT JOIN Customer ON [qSoloVendItemperean-step1].CustomerCode = Customer.No_) LEFT JOIN [Geographical Zone] ON [qSoloVendItemperean-step1].[Geographical Zone] = [Geographical Zone].[Code]) LEFT JOIN [Geographical Zone] AS [Geographical Zone_1] ON [qSoloVendItemperean-step1].[Geographical Zone 2] = [Geographical Zone_1].[Code]) LEFT JOIN Vendor ON Item.[Vendor No_] = Vendor.No_) LEFT JOIN DatiCarryOverESMU ON ([qSoloVendItemperean-step1].ColorCode = DatiCarryOverESMU.[Variable Code 01]) AND ([qSoloVendItemperean-step1].Article = DatiCarryOverESMU.[Model Item No_])) LEFT JOIN [MustBuy-ArticoloColore] ON ([qSoloVendItemperean-step1].[Variable Code 01] = [MustBuy-ArticoloColore].[Variable Code 01]) AND ([qSoloVendItemperean-step1].Article = [MustBuy-ArticoloColore].[Model Item No_])) LEFT JOIN [NavisionEan-step0] ON [qSoloVendItemperean-step1].ItemNo_ = [NavisionEan-step0].[Item No_]) LEFT JOIN [NavisionEan-step0-UPC] ON [qSoloVendItemperean-step1].ItemNo_ = [NavisionEan-step0-UPC].[Item No_]) LEFT JOIN ListinoVenditaWholesale ON [qSoloVendItemperean-step1].ItemNo_ = ListinoVenditaWholesale.[Item No_]) LEFT JOIN ListinoVenditaRetail ON [qSoloVendItemperean-step1].ItemNo_ = ListinoVenditaRetail.[Item No_]
WHERE ((([qSoloVendItemperean-step1].[Bill-to Customer No_])=[forms]![principale]![FiltroClienteEAN]));

